
  // Imagens Alexa em base64
  const alexaImages = {
    pedra:   "data:image/png;base64,",
    papel:   "data:image/png;base64,",
    tesoura: "data:image/png;base64,"
  };

  const playerEmojis = { pedra: "✊", papel: "✋", tesoura: "✌️" };

  const playerDisplay = document.getElementById("playerDisplay");
  const alexaDisplay  = document.getElementById("alexaDisplay");
  const resultBanner  = document.getElementById("result");
  const yourScoreEl   = document.querySelector(".your-score");
  const machineScoreEl= document.querySelector(".machine-score");

  function computerPlay() {
    const choices = ["pedra", "papel", "tesoura"];
    return choices[Math.floor(Math.random() * choices.length)];
  }

  function addScore(el) {
    el.textContent = parseInt(el.textContent) + 1;
    el.closest('.score-card').classList.remove('bump');
    void el.closest('.score-card').offsetWidth;
    el.closest('.score-card').classList.add('bump');
  }

  function setResult(msg, type) {
    resultBanner.textContent = msg;
    resultBanner.className = 'result-banner ' + type;
  }

  function revealAlexa(choice) {
    const img = document.createElement('img');
    img.src = alexaImages[choice];
    img.alt = choice;
    alexaDisplay.innerHTML = '';
    alexaDisplay.appendChild(img);
    alexaDisplay.classList.remove('reveal');
    void alexaDisplay.offsetWidth;
    alexaDisplay.classList.add('reveal');
  }

  function jogar(escolhaJogador) {
    // Desabilita botões durante animação
    document.querySelector('.choices').classList.add('disabled');

    // Destaca botão escolhido
    document.querySelectorAll('.btn-choice').forEach(b => b.classList.remove('selected'));
    document.getElementById(escolhaJogador).classList.add('selected');

    // Mostra escolha do jogador
    playerDisplay.innerHTML = playerEmojis[escolhaJogador];
    playerDisplay.classList.remove('reveal');
    void playerDisplay.offsetWidth;
    playerDisplay.classList.add('reveal');

    // Alexa "pensando"
    alexaDisplay.innerHTML = '🤔';
    alexaDisplay.classList.add('thinking');
    setResult('Alexa está pensando...', '');

    setTimeout(() => {
      const escolhaMaquina = computerPlay();
      alexaDisplay.classList.remove('thinking');
      revealAlexa(escolhaMaquina);

      let msg, tipo;
      if (escolhaJogador === escolhaMaquina) {
        msg = "🤝 Empate! Ninguém pontuou.";
        tipo = 'draw';
      } else if (
        (escolhaJogador === 'pedra'   && escolhaMaquina === 'tesoura') ||
        (escolhaJogador === 'papel'   && escolhaMaquina === 'pedra')   ||
        (escolhaJogador === 'tesoura' && escolhaMaquina === 'papel')
      ) {
        msg = "🎉 Você ganhou essa rodada!";
        tipo = 'win';
        addScore(yourScoreEl);
      } else {
        msg = "😅 Alexa ganhou essa rodada!";
        tipo = 'lose';
        addScore(machineScoreEl);
      }

      setResult(msg, tipo);
      document.querySelector('.choices').classList.remove('disabled');
    }, 900);
  }

  // Eventos
  document.getElementById("pedra").addEventListener("click",   () => jogar("pedra"));
  document.getElementById("papel").addEventListener("click",   () => jogar("papel"));
  document.getElementById("tesoura").addEventListener("click", () => jogar("tesoura"));

  document.getElementById("reset").addEventListener("click", () => {
    const s = parseInt(yourScoreEl.textContent);
    const m = parseInt(machineScoreEl.textContent);
    let msg, tipo;
    if (s === 0 && m === 0) {
      msg = "Escolha sua jogada abaixo!"; tipo = '';
    } else if (s > m) {
      msg = "🏆 Você ganhou a partida! Parabéns!"; tipo = 'win';
    } else if (s < m) {
      msg = "🤖 Alexa ganhou a partida! Tente de novo!"; tipo = 'lose';
    } else {
      msg = "🤝 Partida empatada!"; tipo = 'draw';
    }
    setResult(msg, tipo);
    yourScoreEl.textContent  = 0;
    machineScoreEl.textContent = 0;
    playerDisplay.innerHTML  = '❓';
    alexaDisplay.innerHTML   = '❓';
    document.querySelectorAll('.btn-choice').forEach(b => b.classList.remove('selected'));

    setTimeout(() => {
      if (s !== 0 || m !== 0) {
        setResult("Escolha sua jogada abaixo!", '');
      }
    }, 2500);
  });
